    "EditAuthConfig": {
        "action": "EditAuthConfig",
        "path": "/EditAuthConfig",
        "method": "POST",
        "description": "编辑登录配置",
        "paramKeys": [
            "AnonymousLogin",
            "EmailLogin",
            "EnvId",
            "Mfa",
            "PhoneNumberLogin",
            "PwdUpdateStrategy",
            "UsernameLogin"
        ],
        "requiredKeys": [
            "EnvId"
        ],
        "exampleParams": {
            "AnonymousLogin": "\"TRUE\"",
            "EmailLogin": "\"TRUE\"",
            "EnvId": "lowcode-xxx",
            "Mfa": "无",
            "PhoneNumberLogin": "\"TRUE\"",
            "PwdUpdateStrategy": "无",
            "UsernameLogin": "\"TRUE\""
        },
        "paramsType": "/**\n * 编辑登录配置\n */\ntype EditAuthConfigParams = {\n  /**\n   * 匿名登录配置 \"TRUE\", \"FALSE\"\n   */\n  \"AnonymousLogin\"?: string;\n  /**\n   * 邮箱登录配置 \"TRUE\", \"FALSE\", \"LOGIN_ONLY\"\n   */\n  \"EmailLogin\"?: string;\n  /**\n   * 环境id\n   */\n  \"EnvId\": string;\n  /**\n   * 多因子认证登录配置，用于管理 MFA（Multi-Factor Authentication）相关设置。包括 MFA 总开关、短信验证、邮箱验证、强制绑定手机号、TOTP 动态验证码等认证方式的独立开关配置。当 MFA 总开关（On）开启时，用户在登录后需完成额外的身份验证步骤。各子开关可独立控制具体的验证方式。不传则不修改当前配置。\n   */\n  \"Mfa\"?: {\n    /**\n     * 邮箱验证开关，控制是否在 MFA 流程中启用邮箱验证码校验。取值范围：\n     * TRUE：开启邮箱验证\n     * FALSE：关闭邮箱验证\n     * 不传则不修改当前配置。\n     */\n    \"Email\"?: string | null;\n    /**\n     * MFA 多因子认证开关。取值范围：\n     * TRUE：开启 MFA 多因子认证\n     * FALSE：关闭 MFA 多因子认证\n     * 不传则不修改当前配置。\n     */\n    \"On\"?: string | null;\n    /**\n     * 强制绑定手机号开关，控制用户在完成 MFA 认证前是否必须绑定手机号。取值范围：\n     * TRUE：要求绑定手机号\n     * FALSE：不要求绑定手机号\n     * 不传则不修改当前配置。\n     */\n    \"RequiredBindPhone\"?: string | null;\n    /**\n     * 短信验证开关，控制是否在 MFA 流程中启用短信验证码校验。取值范围：\n     * TRUE：开启短信验证\n     * FALSE：关闭短信验证\n     * 不传则不修改当前配置。\n     */\n    \"Sms\"?: string | null;\n    /**\n     * TOTP 动态验证码开关，控制是否在 MFA 流程中启用基于时间的一次性密码（TOTP）校验。取值范围：\n     * TRUE：开启 TOTP 验证\n     * FALSE：关闭 TOTP 验证\n     * 不传则不修改当前配置。\n     */\n    \"Totp\"?: string | null;\n  };\n  /**\n   * 手机号登录配置 \"TRUE\", \"FALSE\", \"LOGIN_ONLY\"\n   */\n  \"PhoneNumberLogin\"?: string;\n  /**\n   * 登录配置中密码更新配置策略，用于管理使用用户名密码登录方式时，密码的过期策略和更新策略。例如，首次登录需要更新密码、定期过期密码等策略。\n   */\n  \"PwdUpdateStrategy\"?: {\n    /**\n     * 首次登录强制修改密码开关。开启后，用户首次登录时将强制要求修改密码。\n     */\n    \"FirstLoginUpdate\"?: boolean | null;\n    /**\n     * 定期修改密码的周期时间单位，与 PeriodValue 配合使用。取值范围：\n     * WEEK：周\n     * MONTH：月\n     * YEAR：年\n     * 当 PeriodUpdate 为 true 时必填。\n     */\n    \"PeriodType\"?: string | null;\n    /**\n     * 定期强制修改密码开关。开启后，用户需按照 PeriodValue 和 PeriodType 指定的周期定期修改密码，超过周期未修改将在登录时强制要求修改。\n     */\n    \"PeriodUpdate\"?: boolean | null;\n    /**\n     * 定期修改密码的周期数值，与 PeriodType 配合使用。例如 PeriodValue 为 6，PeriodType 为 MONTH，表示每 6 个月需修改一次密码。当 PeriodUpdate 为 true 时必填。\n     */\n    \"PeriodValue\"?: number | null;\n  };\n  /**\n   * 用户名密码登录配置 \"TRUE\", \"FALSE\"\n   */\n  \"UsernameLogin\"?: string;\n};"
    },
